package com.aadil.jobtracker.security;import io.jsonwebtoken.Jwts;import io.jsonwebtoken.SignatureAlgorithm;import io.jsonwebtoken.security.Keys;import org.springframework.stereotype.Component;import java.security.Key;import java.util.Date;@Componentpublic class JwtUtility {    private final Key key=Keys.secretKeyFor(SignatureAlgorithm.HS256);    public String generateTokens(String username){        return Jwts.builder().setSubject(username).setIssuedAt(new Date())                .setExpiration(new Date(System.currentTimeMillis()+1000*60*60)).signWith(key).compact();    }    public String extractUsername(String tokens){        return Jwts.parserBuilder().setSigningKey(key).build().parseClaimsJws(tokens).getBody().getSubject();    }    public boolean validateToken(String token,String username){        return extractUsername(token).equals(username);    }}